import{_ as o,y as l,a as i,o as u,a2 as n,D as a,g as t,I as r}from"./chunks/framework.DCcmcJcL.js";const f=JSON.parse('{"title":"Return Merchandise Authorization (RMA)","description":"","frontmatter":{},"headers":[],"relativePath":"multi-vendor-marketplace/return-merchandise-authorization.md","filePath":"multi-vendor-marketplace/return-merchandise-authorization.md","lastUpdated":1782394364000}'),c={name:"multi-vendor-marketplace/return-merchandise-authorization.md"};function d(h,e,p,g,m,A){const s=l("ImagePopup");return u(),i("div",null,[e[0]||(e[0]=n('<h1 id="return-merchandise-authorization-rma" tabindex="-1">Return Merchandise Authorization (RMA) <a class="header-anchor" href="#return-merchandise-authorization-rma" aria-label="Permalink to &quot;Return Merchandise Authorization (RMA)&quot;">​</a></h1><p>The Return Merchandise Authorization feature allows customers or guests to return products within a defined time period for a refund, replacement, or order cancellation. It provides a simple and structured return request process.</p><p>In the Multi Vendor Marketplace, RMA helps sellers and administrators handle return requests effectively from one location, ensuring clear communication and transparency throughout the return workflow.</p><blockquote><p><strong>Important — RMA is powered by Bagisto core.</strong> The RMA <em>engine</em> — the admin <strong>RMA configuration</strong> (channel/locale settings), <strong>Reasons</strong>, <strong>Rules</strong>, <strong>Statuses</strong>, <strong>Custom Fields</strong>, the admin <strong>Requests</strong> management screens, and the <strong>customer/guest storefront</strong> return-request flow — is now provided by <strong>Bagisto core&#39;s RMA / Returns module</strong>, not by the marketplace package. Please refer to the core RMA documentation for setting up reasons, rules, statuses, custom fields, and for how customers and guests raise return requests from the storefront.</p><p>The marketplace adds <strong>seller scoping</strong> on top of core RMA: each returned item is attributed to the seller who fulfilled it, and sellers get their own RMA management screen in the seller panel (described below).</p></blockquote><h3 id="seller-rma-management" tabindex="-1">Seller RMA Management <a class="header-anchor" href="#seller-rma-management" aria-label="Permalink to &quot;Seller RMA Management&quot;">​</a></h3><p>Sellers can view all RMA requests raised by customers or guests for <strong>their own</strong> products from the <strong>Sales → RMA</strong> section of the seller panel.</p>',6)),a(s,{src:"/images/multi-vendor-marketplace/12-rma-request.webp",alt:"Seller RMA Requests"}),e[1]||(e[1]=t("p",null,"In this section, the seller can view each RMA request along with its RMA ID. To check the complete RMA details, the seller clicks on the view icon.",-1)),a(s,{src:"/images/multi-vendor-marketplace/13-seller-rma-request-view.webp",alt:"Seller RMA Request View"}),e[2]||(e[2]=t("p",null,[r("Using the "),t("strong",null,"Change RMA Status"),r(" option, the seller can update the request status (for example "),t("strong",null,"Pending, Declined, or Item Cancelled"),r("). Under "),t("strong",null,"Status Details"),r(", the seller can also view the current "),t("strong",null,"RMA Status"),r(" and the associated "),t("strong",null,"Order Status"),r(".")],-1)),a(s,{src:"/images/multi-vendor-marketplace/14-rma-view-status.webp",alt:"RMA View Status"}),e[3]||(e[3]=n('<h3 id="rma-status" tabindex="-1">RMA Status <a class="header-anchor" href="#rma-status" aria-label="Permalink to &quot;RMA Status&quot;">​</a></h3><p>When a customer or guest creates a new RMA request, the default RMA status is set to <strong>Pending</strong>. After reviewing the request, the seller updates the RMA status based on the resolution type selected by the customer or guest (Refund, Cancel, or Exchange).</p><h4 id="refund" tabindex="-1">Refund <a class="header-anchor" href="#refund" aria-label="Permalink to &quot;Refund&quot;">​</a></h4><p>When the customer or guest selects <strong>Refund</strong> as the resolution type for a completed order, the seller can progress the request through these statuses:</p><p><strong>1) RMA Request Accepted:</strong> The seller approves the request and changes the status to RMA Approved.</p><p><strong>2) Package Received:</strong> Once the returned product is received, the status is updated to Received Package and the refund process is initiated.</p><p><strong>3) Declined:</strong> If the seller rejects the request, this status is selected.</p><p><strong>4) Solved:</strong> After the refund is successfully completed, the seller marks the request as Solved.</p><h4 id="cancel-items" tabindex="-1">Cancel Items <a class="header-anchor" href="#cancel-items" aria-label="Permalink to &quot;Cancel Items&quot;">​</a></h4><p>When the customer or guest selects <strong>Cancel</strong> as the resolution type for a pending order, the seller can use the following statuses:</p><p><strong>1) RMA Request Accepted:</strong> The seller approves the request and changes the status to RMA Approved.</p>',11)),a(s,{src:"/images/multi-vendor-marketplace/15-rma-request-accept.webp",alt:"RMA Request Accept"}),e[4]||(e[4]=t("p",null,[t("strong",null,"2) Declined:"),r(" If the seller rejects the cancellation request, this status is selected.")],-1)),e[5]||(e[5]=t("p",null,[t("strong",null,"3) Item Cancelled:"),r(" Once the seller accepts the request and cancels the ordered item, this status is applied.")],-1)),a(s,{src:"/images/multi-vendor-marketplace/16-item-cancel.webp",alt:"Item Cancel"}),e[6]||(e[6]=t("p",null,[r("After selecting "),t("strong",null,"Item Cancelled"),r(" and clicking "),t("strong",null,"Save Changes"),r(", the order is cancelled automatically.")],-1)),a(s,{src:"/images/multi-vendor-marketplace/17-canceled-order.webp",alt:"Cancelled Order"}),e[7]||(e[7]=n('<h4 id="exchange" tabindex="-1">Exchange <a class="header-anchor" href="#exchange" aria-label="Permalink to &quot;Exchange&quot;">​</a></h4><p>When the customer or guest selects <strong>Exchange</strong> as the resolution type for a pending order, the seller can update the RMA status as follows:</p><p><strong>1) RMA Request Accepted:</strong> The seller approves the request and changes the status to RMA Approved.</p><p><strong>2) Package Dispatched:</strong> When the seller ships the replacement product, this status is used.</p><p><strong>3) Declined:</strong> If the seller rejects the exchange request, this status is selected.</p><p><strong>4) Solved:</strong> After the customer or guest receives the exchanged product, the seller marks the RMA as Solved.</p><blockquote><p><strong>Note:</strong> The admin can review and manage the same return requests (with seller attribution) from <strong>Bagisto core&#39;s RMA / Returns</strong> section in the admin panel.</p></blockquote>',7))])}const M=o(c,[["render",d]]);export{f as __pageData,M as default};
